package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = new StringBuilder();
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecord_withNonNullValues() throws Exception {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format);

        // Use reflection to override print and println behavior by replacing private fields with proxies
        // Create proxies for print and println by reflection on CSVPrinter instance

        // Override print(Object) method by reflection: replace the private 'out' field with a custom Appendable
        // that appends directly without any escaping or formatting.

        // Create a custom Appendable that appends raw values
        class RawAppendable implements Appendable {
            private final StringBuilder sb;

            RawAppendable(StringBuilder sb) {
                this.sb = sb;
            }

            @Override
            public Appendable append(CharSequence csq) {
                sb.append(csq);
                return this;
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                sb.append(csq, start, end);
                return this;
            }

            @Override
            public Appendable append(char c) {
                sb.append(c);
                return this;
            }
        }

        RawAppendable rawAppendable = new RawAppendable(appendable);

        // Replace the private final 'out' field inside csvPrinter with rawAppendable
        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);

        // Remove final modifier via reflection
        // (Optional step, sometimes needed depending on JVM)
        // But here just setAccessible(true) usually works.
        outField.set(csvPrinter, rawAppendable);

        // Now override print(Object) and println() methods by reflection to do raw append
        // Since methods are final/private, we cannot override them directly.
        // Instead, we invoke printRecord normally, and because 'out' is replaced with rawAppendable,
        // the output will be raw concatenation.

        csvPrinter.printRecord("a", 123, true);

        assertEquals("a123true\n", appendable.toString());
    }

    @Test
    void testPrintRecord_withNullValues() throws Exception {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format);

        class RawAppendable implements Appendable {
            private final StringBuilder sb;

            RawAppendable(StringBuilder sb) {
                this.sb = sb;
            }

            @Override
            public Appendable append(CharSequence csq) {
                sb.append(csq);
                return this;
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                sb.append(csq, start, end);
                return this;
            }

            @Override
            public Appendable append(char c) {
                sb.append(c);
                return this;
            }
        }

        RawAppendable rawAppendable = new RawAppendable(appendable);

        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        outField.set(csvPrinter, rawAppendable);

        csvPrinter.printRecord("a", null, "c");

        assertEquals("anullc\n", appendable.toString());
    }

    @Test
    void testPrintRecord_withEmptyValues() throws Exception {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format);

        class RawAppendable implements Appendable {
            private final StringBuilder sb;

            RawAppendable(StringBuilder sb) {
                this.sb = sb;
            }

            @Override
            public Appendable append(CharSequence csq) {
                sb.append(csq);
                return this;
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                sb.append(csq, start, end);
                return this;
            }

            @Override
            public Appendable append(char c) {
                sb.append(c);
                return this;
            }
        }

        RawAppendable rawAppendable = new RawAppendable(appendable);

        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        outField.set(csvPrinter, rawAppendable);

        csvPrinter.printRecord();

        assertEquals("\n", appendable.toString());
    }
}
